    if (actualCloseEvents.mouseleave) {
      addDelegatedHoverCloseListener()
    }
    if (actualOpenEvents.mouseover) {
      addDelegatedHoverOpenListener()
    }
    if (actualCloseEvents.mouseout) {
      addDelegatedHoverCloseListener()
    }
